async (params, browser) => {
  // Search Twitch
  await browser.open(`https://www.twitch.tv/search?term=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[class*=\'search-result\'], [class*=\'SearchResults\'], [data-a-target*=\'search\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const cards = document.querySelectorAll('[class*="search-result"] article, [class*="SearchResultCard"], [data-a-target*="search-result"], [class*="tw-tower"] > div'); for (let i = 0; i < Math.min(cards.length, 15); i++) { const el = cards[i]; const nameEl = el.querySelector('a[data-a-target="preview-card-channel-link"], [class*="channel-name"], h3, [data-a-target="preview-card-title-link"]'); const gameEl = el.querySelector('[data-a-target="preview-card-game-link"], [class*="game-name"], a[href*="/directory/"]'); const viewersEl = el.querySelector('[class*="viewer"], [class*="stream-viewers"], [aria-label*="viewer"]'); const linkEl = el.querySelector('a[href]'); const imgEl = el.querySelector('img'); const liveEl = el.querySelector('[class*="live"], [class*="LiveIndicator"]'); results.push({ name: nameEl ? nameEl.textContent.trim() : '', game: gameEl ? gameEl.textContent.trim() : '', viewers: viewersEl ? viewersEl.textContent.trim() : '', is_live: !!liveEl, url: linkEl ? linkEl.href : '', thumbnail: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
